const sortableElements = document.querySelectorAll('#demo-tabpane-list .list-group-item');
console.log('Sortable elements found:', sortableElements.length);

// 获取 One 和 Three 元素
let oneElement = null;
let threeElement = null;

sortableElements.forEach((el, index) => {
    console.log(`Element ${index}: "${el.textContent.trim()}"`);
    if (el.textContent.trim() === 'One') {
        oneElement = el;
    }
    if (el.textContent.trim() === 'Three') {
        threeElement = el;
    }
});

if (oneElement && threeElement) {
    console.log('Found One and Three elements');
    // 创建拖拽事件
    const oneRect = oneElement.getBoundingClientRect();
    const threeRect = threeElement.getBoundingClientRect();

    // 创建拖拽开始事件
    const dragStart = new DragEvent('dragstart', {
        bubbles: true,
        cancelable: true,
        dataTransfer: new DataTransfer()
    });

    // 创建拖拽结束事件 - 拖拽到Three的下方
    const drop = new DragEvent('drop', {
        bubbles: true,
        cancelable: true,
        clientX: threeRect.left + threeRect.width / 2,
        clientY: threeRect.bottom + 10
    });

    // 执行拖拽
    oneElement.dispatchEvent(dragStart);
    threeElement.dispatchEvent(drop);

    console.log('Drag and drop executed');
} else {
    console.log('Could not find One or Three elements');
}"})

