const threeItem = Array.from(document.querySelectorAll('.list-group-item')).find(el => el.textContent.trim() === 'Three');

if (oneItem && threeItem) {
    console.log('Found items');

    // 获取父容器
    const container = oneItem.parentElement;

    // 移动 One 到 Three 的后面
    const fourItem = threeItem.nextElementSibling;
    if (fourItem) {
        container.insertBefore(oneItem, fourItem);
    } else {
        container.appendChild(oneItem);
    }

    console.log('Moved One after Three');
} else {
    console.log('Items not found');
}"})

